/**
 * Financial Calculator — deterministic math for retirement projections.
 *
 * All numbers produced here are computed, not generated by an LLM.
 * The LLM is only used for the narrative summary after these values are known.
 *
 * Assumptions:
 *   - Annual investment return: 7% (long-term S&P 500 average, inflation-adjusted)
 *   - Withdrawal rule: 4% SWR (Safe Withdrawal Rate — "25x rule")
 *   - Savings = monthly income minus monthly expenses (all excess income is saved/invested)
 */

const ANNUAL_RETURN_RATE = 0.07;
const SAFE_WITHDRAWAL_RATE = 0.04;
const REQUIRED_MULTIPLE = 1 / SAFE_WITHDRAWAL_RATE; // 25

/**
 * Future value of a lump sum invested today.
 *   FV = PV × (1 + r)^n
 */
function futureValueLumpSum(presentValue, annualRate, years) {
  return presentValue * Math.pow(1 + annualRate, years);
}

/**
 * Future value of regular annual contributions.
 *   FV = PMT × [((1 + r)^n - 1) / r]
 */
function futureValueAnnuity(annualContribution, annualRate, years) {
  if (annualContribution <= 0 || years <= 0) return 0;
  return annualContribution * ((Math.pow(1 + annualRate, years) - 1) / annualRate);
}

/**
 * Project savings at a future point in time.
 * @param {number} currentSavings      Today's total savings/investments
 * @param {number} annualContribution  Amount saved per year going forward
 * @param {number} years               Years until the target date
 * @returns {number}
 */
function projectSavings(currentSavings, annualContribution, years) {
  return Math.round(
    futureValueLumpSum(currentSavings, ANNUAL_RETURN_RATE, years) +
    futureValueAnnuity(annualContribution, ANNUAL_RETURN_RATE, years),
  );
}

/**
 * Run the full retirement projection for a user profile.
 *
 * @param {object} profile   { age, income, savings, monthly_expenses, retirement_age }
 * @returns {object}         All projection numbers (no LLM involved)
 */
export function calculateRetirementProjection(profile) {
  const age            = Number(profile.age)             || 35;
  const income         = Number(profile.income)          || 0;
  const currentSavings = Number(profile.savings)         || 0;
  const monthlyExpenses = Number(profile.monthly_expenses) || 0;
  const retirementAge  = Number(profile.retirement_age)  || 65;

  const yearsToRetirement  = Math.max(0, retirementAge - age);
  const monthlyIncome      = income / 12;
  const monthlySavings     = Math.max(0, monthlyIncome - monthlyExpenses);
  const annualSavings      = monthlySavings * 12;
  const annualExpenses     = monthlyExpenses * 12;

  // ── Core projection ───────────────────────────────────────────────────────
  const projectedSavings = projectSavings(currentSavings, annualSavings, yearsToRetirement);

  // ── Retirement viability (4% SWR / 25x rule) ─────────────────────────────
  const requiredSavings  = Math.round(annualExpenses * REQUIRED_MULTIPLE);
  const canRetire        = projectedSavings >= requiredSavings;
  const savingsGap       = Math.max(0, requiredSavings - projectedSavings);

  // ── Monthly income at retirement (4% annual withdrawal / 12) ─────────────
  const monthlyRetirementIncome  = (projectedSavings * SAFE_WITHDRAWAL_RATE) / 12;
  const monthlyShortfallOrSurplus = Math.round(monthlyRetirementIncome - monthlyExpenses);

  // ── Years of runway (how long savings last without investment returns) ────
  const yearsOfRunway = annualExpenses > 0
    ? Math.round(projectedSavings / annualExpenses)
    : 999;

  // ── 3 milestones at equal intervals ──────────────────────────────────────
  const currentYear = new Date().getFullYear();
  const intervals   = [1/3, 2/3, 1].map(f => Math.round(yearsToRetirement * f));

  const milestones = intervals.map((y) => ({
    year:    currentYear + y,
    savings: projectSavings(currentSavings, annualSavings, y),
  }));

  return {
    // Core results
    can_retire_at_target:            canRetire,
    projected_savings_at_retirement: projectedSavings,
    required_savings_at_retirement:  requiredSavings,
    savings_gap:                     savingsGap,
    monthly_shortfall_or_surplus:    monthlyShortfallOrSurplus,
    years_of_runway:                 yearsOfRunway,
    milestones,
    // Inputs (passed to LLM for context when generating summary)
    _inputs: {
      age, income, currentSavings, monthlyExpenses, retirementAge,
      yearsToRetirement, monthlySavings, annualSavings,
      assumedAnnualReturn: `${(ANNUAL_RETURN_RATE * 100).toFixed(0)}%`,
      withdrawalRule:      `${(SAFE_WITHDRAWAL_RATE * 100).toFixed(0)}% SWR (25x rule)`,
    },
  };
}
